private struct PinterestFeedScreen: View {
    var body: some View {
        NavigationStack {
            ScrollView {
                VStack(spacing: 0) {
                    PinterestStoriesBar()
                    ForEach(PinterestDemoData.posts) { post in
                        PinterestPostCard(post: post, accent: PinterestTokens.pinterestTextPrimaryLight, textSec: PinterestTokens.pinterestTextSecondaryLight)
                        Divider().background(PinterestTokens.pinterestTextSecondaryLight.opacity(0.3))
                    }
                }
            }
            .background(PinterestTokens.pinterestCanvasLight.ignoresSafeArea())
            .navigationTitle("Pinterest")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .topBarLeading) { Image(systemName: "camera").foregroundStyle(PinterestTokens.pinterestTextPrimaryLight) }
                ToolbarItem(placement: .topBarTrailing) {
                    HStack(spacing: 16) {
                        Image(systemName: "heart")
                        Image(systemName: "paperplane")
                    }
                }
            }
        }
    }
}

private struct PinterestStoriesBar: View {
    private let stories = PinterestDemoData.stories
    var body: some View {
        ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 14) {
                ForEach(stories) { story in
                    VStack(spacing: 4) {
                        ZStack {
                            Circle().strokeBorder(
                                AngularGradient(colors: [.orange, .pink, .purple, .blue, .orange], center: .center),
                                lineWidth: story.unread ? 2.5 : 1
                            ).frame(width: 68, height: 68)
                            Circle().fill(story.color.gradient).frame(width: 60, height: 60)
                                .overlay(Text(story.initials).font(.system(size: 20, weight: .semibold)).foregroundStyle(.white))
                        }
                        Text(story.name).font(.system(size: 11)).lineLimit(1).frame(width: 72)
                    }
                }
            }
            .padding(.horizontal, 12).padding(.vertical, 10)
        }
    }
}

private struct PinterestPostCard: View {
    let post: PinterestPost
    let accent: Color
    let textSec: Color
    @State private var liked = false
    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack {
                Circle().fill(post.avatarColor.gradient).frame(width: 32, height: 32)
                    .overlay(Text(post.initials).font(.system(size: 12, weight: .bold)).foregroundStyle(.white))
                Text(post.username).font(PinterestFonts.pinterestUsername)
                Spacer()
                Image(systemName: "ellipsis")
            }
            .padding(.horizontal, 12)
            RoundedRectangle(cornerRadius: 0).fill(post.avatarColor.opacity(0.25)).frame(height: 320)
                .overlay { Image(systemName: "photo").font(.system(size: 48)).foregroundStyle(textSec) }
            HStack(spacing: 16) {
                Button { liked.toggle() } label: { Image(systemName: liked ? "heart.fill" : "heart").foregroundStyle(liked ? .red : .primary) }
                Image(systemName: "bubble.right")
                Image(systemName: "paperplane")
                Spacer()
                Image(systemName: "bookmark")
            }
            .font(.system(size: 22)).padding(.horizontal, 12)
            Text("\(post.likes + (liked ? 1 : 0)) J'aime").font(.system(size: 14, weight: .semibold)).padding(.horizontal, 12)
            Text(post.caption).font(.system(size: 14)).padding(.horizontal, 12).padding(.bottom, 12)
        }
    }
}

